export function escapeHtml(e){return String(e).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;")}export function debounce(e,t){let c=null;const r=(...r)=>{c&&clearTimeout(c),c=window.setTimeout((()=>{e(...r)}),t)};return r.cancel=()=>{c&&clearTimeout(c)},r}